INSERT INTO lead_stage_history (lead_id, from_stage, to_stage, from_board_id, to_board_id, changed_by, changed_at, notes) SELECT l.id, 'active', l.lead_status, l.board_id, l.board_id, l.created_by, l.updated_at, CASE l.lead_status WHEN 'closed' THEN 'Lead fechado (retroativo)' WHEN 'refused' THEN 'Lead recusado (retroativo)' END FROM leads l WHERE l.lead_status IN ('closed', 'refused') AND NOT EXISTS (SELECT 1 FROM lead_stage_history h WHERE h.lead_id = l.id AND h.to_stage = l.lead_status);